import React from 'react';
import { crmPricing, pricingLastUpdated } from '../data/crmPricing';

const AboutPage = () => {
  return (
    <section>
      <div className="page-header">
        <div>
          <h2>О проекте</h2>
          <p>
            Платформа помогает выбрать CRM на основе взвешенной оценки критериев
            и экономического эффекта внедрения.
          </p>
        </div>
      </div>

      <div className="panel">
        <p className="panel-title">Архитектура</p>
        <p className="panel-text">
          React (Frontend) → Express REST API (Backend) → PostgreSQL (Data Layer)
        </p>
      </div>

      <div className="panel">
        <div className="panel-head-row">
          <p className="panel-title">Актуальные цены по конфигурациям</p>
          <span className="badge">Обновлено: {pricingLastUpdated}</span>
        </div>

        <div className="pricing-grid">
          {crmPricing.map((crm) => (
            <article key={crm.crm} className="pricing-card">
              <div className="pricing-card-head">
                <p className="pricing-name">{crm.crm}</p>
                <a href={crm.source} target="_blank" rel="noreferrer">Источник</a>
              </div>
              {crm.configs.map((config) => (
                <div key={`${crm.crm}-${config.name}`} className="pricing-row">
                  <span>{config.name}</span>
                  <span>
                    {config.price} ₽ {config.period}
                    {config.promoPrice ? ` • акция ${config.promoPrice} ₽` : ''}
                    {config.oldPrice ? ` • было ${config.oldPrice} ₽` : ''}
                  </span>
                </div>
              ))}
              {crm.note && <p className="stat-note">{crm.note}</p>}
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default AboutPage;
